#include <bits/stdc++.h>
using namespace std;

const int N=105;

int n,t,ans,match[N*N];
bool b[N][N],vis[N*N];
vector<int> g[N*N];

inline int cal(int x,int y){
    return (x-1)*n+y;
}

bool dfs(int x){
    for(int y:g[x])
        if(!vis[y]){
            vis[y]=1;
            if(!match[y] || dfs(match[y])){
                match[y]=x;
                return 1;
            }
        }
    return 0;
}

int main(){
    scanf("%d%d",&n,&t);
    while(t--){
        int x,y;
        scanf("%d%d",&x,&y);
        b[x][y]=1;
    }
    for(int i=1;i<=n;i++)
        for(int j=(i%2?1:2);j<=n;j+=2){
            if(j>1 && !b[i][j] && !b[i][j-1])
                g[cal(i,j)].push_back(cal(i,j-1));
            if(j<n && !b[i][j] && !b[i][j+1])
                g[cal(i,j)].push_back(cal(i,j+1));
            if(i>1 && !b[i][j] && !b[i-1][j])
                g[cal(i,j)].push_back(cal(i-1,j));
            if(i<n && !b[i][j] && !b[i+1][j])
                g[cal(i,j)].push_back(cal(i+1,j));
        }
    for(int i=1;i<=n;i++)
        for(int j=(i%2?1:2);j<=n;j+=2){
            memset(vis,0,sizeof(vis));
            if(dfs(cal(i,j)))
                ans++;
        }
    printf("%d",ans);
    return 0;
}
